def apply_translations(html, trans_dict):
    """Apply translations, longest first."""
    items = sorted(trans_dict.items(), key=lambda x: len(x[0]), reverse=True)
    for en, tr in items:
        if en in html:
            html = html.replace(en, tr)
    return html

def main():
    with open('index.html', 'r', encoding='utf-8') as f:
        en_html = f.read()
    
    for lang in LANGS:
        print(f"\n=== Processing {lang} ===")
        
        lang_path = f"{lang}/index.html"
        if not os.path.exists(lang_path):
            os.makedirs(lang, exist_ok=True)
            lang_html = en_html
        else:
            with open(lang_path, 'r', encoding='utf-8') as f:
                lang_html = f.read()
        
        # Apply complete translations
        trans = COMPLETE_TRANS.get(lang, {})
        lang_html = apply_translations(lang_html, trans)
        
        # Update meta tags
        lang_html = lang_html.replace('lang="en"', f'lang="{lang}"')
        
        # Write back
        with open(lang_path, 'w', encoding='utf-8') as f:
            f.write(lang_html)
        
        print(f"  Done - applied {len(trans)} translations")

if __name__ == '__main__':
    main()
